import fs from "node:fs";
import os from "node:os";
import path from "node:path";

// Base64 encoded 'Review is required' (Samantha voice, M4A/AAC format)
const REVIEW_SOUND_B64 =
  "|";

// Base64 encoded 'All tasks completed' (macOS say voice, M4A/AAC format)
const DONE_SOUND_B64 =
  "";

// Base64 encoded 'Loop stopped due to error' (macOS say voice, M4A/AAC format)
const FAILED_SOUND_B64 =
  "";

function getAssetsDir() {
  const dir = path.join(os.homedir(), ".agent-team", "assets");
  if (!fs.existsSync(dir)) {
    fs.mkdirSync(dir, { recursive: true });
  }
  return dir;
}

export function extractReviewSound() {
  extractAsset("review.m4a", REVIEW_SOUND_B64);
  extractAsset("done.m4a", DONE_SOUND_B64);
  extractAsset("failed.m4a", FAILED_SOUND_B64);
  return path.join(getAssetsDir(), "review.m4a");
}

function extractAsset(filename: string, b64: string): void {
  const target = path.join(getAssetsDir(), filename);
  if (fs.existsSync(target)) return;
  fs.writeFileSync(target, Buffer.from(b64, "base64"));
}
